import html2pdf from 'html2pdf.js';

import {
  Filesystem,
    Directory,
    } from '@capacitor/filesystem';

    import {
      Share,
      } from '@capacitor/share';

      const safeFileName = (name: string) =>
        name
            .replace(/[\\/:*?"<>|]/g, '')
                .replace(/\s+/g, '_');

                const blobToBase64 = (
                  blob: Blob
                  ): Promise<string> => {
                    return new Promise((resolve, reject) => {
                        const reader = new FileReader();

                            reader.onloadend = () => {
                                  const result = reader.result as string;

                                        const base64 =
                                                result.split(',')[1] || '';

                                                      resolve(base64);
                                                          };

                                                              reader.onerror = reject;
                                                                  reader.readAsDataURL(blob);
                                                                    });
                                                                    };

                                                                    export async function sharePdfFromElement(
                                                                      elementId = 'print-report',
                                                                        title = 'كشف حساب'
                                                                        ) {
                                                                          const element =
                                                                              document.getElementById(elementId);

                                                                                if (!element) {
                                                                                    alert('منطقة التقرير غير موجودة');
                                                                                        return;
                                                                                          }

                                                                                            let wrapper: HTMLDivElement | null = null;

                                                                                              try {
                                                                                                  const clone =
                                                                                                        element.cloneNode(true) as HTMLElement;

                                                                                                            clone
                                                                                                                  .querySelectorAll('.no-print, button')
                                                                                                                        .forEach((el) => el.remove());

                                                                                                                            clone.style.width = '720px';
                                                                                                                                clone.style.maxWidth = '720px';
                                                                                                                                    clone.style.minHeight = 'auto';
                                                                                                                                        clone.style.background = '#ffffff';
                                                                                                                                            clone.style.color = '#111111';
                                                                                                                                                clone.style.padding = '12px';
                                                                                                                                                    clone.style.margin = '0 auto';
                                                                                                                                                        clone.style.direction = 'rtl';
                                                                                                                                                            clone.style.boxSizing = 'border-box';
                                                                                                                                                                clone.style.fontFamily =
                                                                                                                                                                      'Cairo,Tahoma,Arial,sans-serif';

                                                                                                                                                                          clone
                                                                                                                                                                                .querySelectorAll<HTMLElement>(
                                                                                                                                                                                        '.card, .app-card'
                                                                                                                                                                                              )
                                                                                                                                                                                                    .forEach((el) => {
                                                                                                                                                                                                            el.style.boxShadow = 'none';
                                                                                                                                                                                                                    el.style.background = '#ffffff';
                                                                                                                                                                                                                            el.style.boxSizing = 'border-box';
                                                                                                                                                                                                                                  });

                                                                                                                                                                                                                                      clone
                                                                                                                                                                                                                                            .querySelectorAll<HTMLElement>(
                                                                                                                                                                                                                                                    '.table-wrap'
                                                                                                                                                                                                                                                          )
                                                                                                                                                                                                                                                                .forEach((el) => {
                                                                                                                                                                                                                                                                        el.style.overflow = 'visible';
                                                                                                                                                                                                                                                                                el.style.width = '100%';
                                                                                                                                                                                                                                                                                        el.style.maxWidth = '100%';
                                                                                                                                                                                                                                                                                              });

                                                                                                                                                                                                                                                                                                  clone
                                                                                                                                                                                                                                                                                                        .querySelectorAll<HTMLElement>(
                                                                                                                                                                                                                                                                                                                'table'
                                                                                                                                                                                                                                                                                                                      )
                                                                                                                                                                                                                                                                                                                            .forEach((el) => {
                                                                                                                                                                                                                                                                                                                                    el.style.width = '100%';
                                                                                                                                                                                                                                                                                                                                            el.style.maxWidth = '100%';
                                                                                                                                                                                                                                                                                                                                                    el.style.minWidth = '0';
                                                                                                                                                                                                                                                                                                                                                            el.style.tableLayout = 'fixed';
                                                                                                                                                                                                                                                                                                                                                                    el.style.borderCollapse = 'collapse';
                                                                                                                                                                                                                                                                                                                                                                            el.style.pageBreakInside = 'auto';
                                                                                                                                                                                                                                                                                                                                                                                  });

                                                                                                                                                                                                                                                                                                                                                                                      clone
                                                                                                                                                                                                                                                                                                                                                                                            .querySelectorAll<HTMLElement>(
                                                                                                                                                                                                                                                                                                                                                                                                    'th, td'
                                                                                                                                                                                                                                                                                                                                                                                                          )
                                                                                                                                                                                                                                                                                                                                                                                                                .forEach((el) => {
                                                                                                                                                                                                                                                                                                                                                                                                                        el.style.fontSize = '10px';
                                                                                                                                                                                                                                                                                                                                                                                                                                el.style.padding = '6px 3px';
                                                                                                                                                                                                                                                                                                                                                                                                                                        el.style.wordBreak = 'break-word';
                                                                                                                                                                                                                                                                                                                                                                                                                                                el.style.overflowWrap = 'anywhere';
                                                                                                                                                                                                                                                                                                                                                                                                                                                        el.style.boxSizing = 'border-box';
                                                                                                                                                                                                                                                                                                                                                                                                                                                              });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                  clone
                                                                                                                                                                                                                                                                                                                                                                                                                                                                        .querySelectorAll<HTMLElement>(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                'tr, .card, .app-card'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      )
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            .forEach((el) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    el.style.pageBreakInside = 'avoid';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            el.style.breakInside = 'avoid';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      wrapper =
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            document.createElement('div');

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                wrapper.style.position = 'fixed';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    wrapper.style.left = '-99999px';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        wrapper.style.top = '0';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            wrapper.style.width = '720px';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                wrapper.style.background = '#ffffff';
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    wrapper.style.zIndex = '-1';

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        wrapper.appendChild(clone);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            document.body.appendChild(wrapper);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const fileName =
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      `${safeFileName(title)}.pdf`;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const blob: Blob = await html2pdf()
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                .set({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        margin: [5, 5, 5, 5],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                filename: fileName,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        image: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  type: 'jpeg',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            quality: 0.98,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            html2canvas: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      scale: 2,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                useCORS: true,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          backgroundColor: '#ffffff',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    windowWidth: 740,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              scrollX: 0,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        scrollY: 0,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        jsPDF: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  unit: 'mm',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            format: 'a4',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      orientation: 'portrait',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      pagebreak: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                mode: ['avoid-all', 'css', 'legacy'],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          avoid: [
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      'tr',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  'table',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              '.card',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          '.app-card',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      '.section-row',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    .from(clone)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          .outputPdf('blob');

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const base64 =
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    await blobToBase64(blob);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        try {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const saved =
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      await Filesystem.writeFile({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                path: fileName,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          data: base64,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    directory: Directory.Cache,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              recursive: true,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            await Share.share({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    title,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            text: title,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    url: saved.uri,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            dialogTitle: 'مشاركة PDF',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            } catch {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  const file =
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          new File(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    [blob],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              fileName,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    type: 'application/pdf',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      );

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    navigator.share &&
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            navigator.canShare &&
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    navigator.canShare({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              files: [file],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    await navigator.share({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              title,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        text: title,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  files: [file],
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  return;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const url =
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      URL.createObjectURL(blob);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const a =
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    document.createElement('a');

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          a.href = url;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                a.download = fileName;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      a.click();

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            URL.revokeObjectURL(url);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  alert(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          'تم إنشاء ملف PDF. يمكنك مشاركته من ملفات الهاتف.'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      } catch (error) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          console.error(error);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              alert('تعذرت مشاركة ملف PDF');
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                } finally {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    if (wrapper) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          document.body.removeChild(wrapper);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }